mapper.select:
SELECT eos.OPER_ID AS operId, eos.PLANT_CD AS plantCd, eos.EQUIPMENT_CD AS equipmentCd, eos.OPER_DT AS operDt, eos.SHIFT AS shift, eos.OPER_STATUS AS operStatus, eos.START_DTM AS startDtm, eos.END_DTM AS endDtm, eos.OPER_TIME AS operTime, eos.WO_ID AS woId, eos.ITEM_CD AS itemCd, eos.PROD_QTY AS prodQty, eos.WORKER_ID AS workerId, eos.OPER_RMK AS operRmk, eos.REG_DTM AS regDtm FROM EQP_OPER_STATUS eos WHERE 1 = 1
AND eos.PLANT_CD = #{plantCd}
AND eos.EQUIPMENT_CD = #{equipmentCd}
AND eos.OPER_DT >= #{fromDt}
AND eos.OPER_DT <= #{toDt}
ORDER BY eos.OPER_DT DESC, eos.OPER_ID DESC

SELECT eos.OPER_ID AS operId, eos.PLANT_CD AS plantCd, eos.EQUIPMENT_CD AS equipmentCd, eos.OPER_DT AS operDt, eos.SHIFT AS shift, eos.OPER_STATUS AS operStatus, eos.START_DTM AS startDtm, eos.END_DTM AS endDtm, eos.OPER_TIME AS operTime, eos.WO_ID AS woId, eos.ITEM_CD AS itemCd, eos.PROD_QTY AS prodQty, eos.WORKER_ID AS workerId, eos.OPER_RMK AS operRmk, eos.REG_DTM AS regDtm FROM EQP_OPER_STATUS eos WHERE 1 = 1
AND eos.PLANT_CD = #{plantCd}
AND eos.EQUIPMENT_CD = #{equipmentCd}
AND eos.OPER_DT >= #{fromDt}
AND eos.OPER_DT <= #{toDt}
ORDER BY eos.OPER_DT DESC, eos.OPER_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM EQP_OPER_STATUS eos
WHERE 1 = 1

    AND eos.PLANT_CD = #{plantCd}


    AND eos.EQUIPMENT_CD = #{equipmentCd}


    AND eos.OPER_DT >= #{fromDt}


    AND eos.OPER_DT <= #{toDt}

