mapper.select:
SELECT ed.DOWNTIME_ID AS downtimeId, ed.PLANT_CD AS plantCd, ed.EQUIPMENT_CD AS equipmentCd, ed.DOWNTIME_DT AS downtimeDt, ed.DOWNTIME_TYPE AS downtimeType, ed.DOWNTIME_CD AS downtimeCd, ed.DOWNTIME_REASON AS downtimeReason, ed.START_DTM AS startDtm, ed.END_DTM AS endDtm, ed.DOWNTIME_MIN AS downtimeMin, ed.WO_ID AS woId, ed.ACTION_CONTENT AS actionContent, ed.REG_DTM AS regDtm FROM EQP_DOWNTIME ed WHERE 1 = 1
AND ed.PLANT_CD = #{plantCd}
AND ed.EQUIPMENT_CD = #{equipmentCd}
AND ed.DOWNTIME_DT >= #{fromDt}
AND ed.DOWNTIME_DT <= #{toDt}
ORDER BY ed.DOWNTIME_DT DESC, ed.DOWNTIME_ID DESC

SELECT emh.MAINT_ID AS maintId, emh.PLANT_CD AS plantCd, emh.EQUIPMENT_CD AS equipmentCd, emh.MAINT_NO AS maintNo, emh.MAINT_TYPE AS maintType, emh.MAINT_DT AS maintDt, emh.START_DTM AS startDtm, emh.END_DTM AS endDtm, emh.MAINT_TIME AS maintTime, emh.MAINT_WORKER_ID AS maintWorkerId, emh.MAINT_RESULT AS maintResult, emh.MAINT_COST AS maintCost, emh.REG_DTM AS regDtm FROM EQP_MAINT_HIS emh WHERE 1 = 1
AND emh.PLANT_CD = #{plantCd}
AND emh.EQUIPMENT_CD = #{equipmentCd}
AND emh.MAINT_DT >= #{fromDt}
AND emh.MAINT_DT <= #{toDt}
ORDER BY emh.MAINT_DT DESC, emh.MAINT_ID DESC

SELECT COUNT(*)
FROM EQP_MAINT_HIS
WHERE MAINT_DT = #{maintDt}
